CREATE DATABASE SALES_PROJECT;USE SALES_PROJECT;SELECT * FROM superstore_sales;-- Total salesSELECT SUM(sales) as Total_SalesFROM superstore_sales;-- Top selling ProductsSELECT `Product Name` , SUM(sales) as Total_SalesFROM superstore_SalesGROUP BY `Product Name`ORDER BY SUM(sales) DESC;-- Region wise SalesSELECT region , SUM(sales) as Total_SalesFROM superstore_salesGROUP BY region